@app.api_route("/api/{path:path}", methods=["GET", "POST", "PUT", "PATCH", "DELETE"])
async def api_proxy(path: str, request: Request) -> Response:
    headers = {k: v for k, v in request.headers.items() if k.lower() not in {"host", "content-length", "x-api-key"}}
    if MINYAD_API_SECRET:
        headers["X-API-Key"] = MINYAD_API_SECRET
    try:
        async with httpx.AsyncClient(base_url=API_BASE_URL, timeout=10.0) as client:
            response = await client.request(request.method, f"/{path}", params=request.query_params, content=await request.body(), headers=headers)
    except httpx.RequestError as exc:
        return JSONResponse(status_code=502, content={"detail": "Unable to reach Minyad API service", "api_base_url": API_BASE_URL, "error": str(exc)})
    excluded = {"content-encoding", "content-length", "transfer-encoding", "connection"}
    return Response(content=response.content, status_code=response.status_code, headers={k: v for k, v in response.headers.items() if k.lower() not in excluded}, media_type=response.headers.get("content-type"))


